#include<bits/stdc++.h>
using namespace std;
int n,q;
int s;
int a[1005];
int main() {
	int d[] = {0, 10, 100, 1000, 10000, 100000, 1000000, 10000000, 100000000};
	cin>>n>>q;
	for(int i=1; i<=n; i++) {
		cin>>a[i];
	}
	for (int i = 1; i <= q; i++) {
		int x, y;
		cin >> x >> y;
		s=0;
		for (int j = 1; j <= n; j++) {
			int h = a[j] % d[x];
			if (h == y) {
				s++;
			}
		}
		cout<<s<<endl;
	}
	return 0;
}
